 const state = { agencies: AGENCIES, sort:'value', search:'', expanded:null };
 const $ = (sel) => document.querySelector(sel);
 const $$ = (sel) => Array.from(document.querySelectorAll(sel));
 const fmt = (n) => Number(n).toLocaleString('en-US');
 function rankByValue(list, baseline=false){
 const source = baseline ? list.filter(a => Number(a.baselineValue || 0) > 0) : list;
 const ranked = [...source].sort((a,b)=>{
 const av = baseline ? a.baselineValue : a.metalValue;
 const bv = baseline ? b.baselineValue : b.metalValue;
 const ae = baseline ? a.baselineEfficiencyBonus : a.efficiencyBonus;
 const be = baseline ? b.baselineEfficiencyBonus : b.efficiencyBonus;
 const ap = baseline ? a.baselineMetalPoints : a.metalPoints;
 const bp = baseline ? b.baselineMetalPoints : b.metalPoints;
 return bv-av || be-ae || bp-ap || b.gp-a.gp || a.agency.localeCompare(b.agency);
 });
 const map = new Map();
 ranked.forEach((a,i)=>map.set(a.agency, i+1));
 return map;
 }
 const currentValueRank = rankByValue(AGENCIES, false);
 const previousValueRank = rankByValue(AGENCIES, true);
 AGENCIES.forEach(a=>{
 const hadPreviousRank = Number(a.baselineValue || 0) > 0 && previousValueRank.has(a.agency);
 a.previousRank = hadPreviousRank ? previousValueRank.get(a.agency) : null;
 a.currentRank = currentValueRank.get(a.agency);
 a.rankMove = hadPreviousRank ? (a.previousRank - a.currentRank) : null;
 });
 function momentumHtml(a){
 if(a.rankMove === null || a.rankMove === undefined){
 return `<span class="move flat" title="New in current ranking">—</span>`;
 }
 const d = a.rankMove || 0;
 const cls = d > 0 ? 'up' : d < 0 ? 'down' : 'flat';
 const label = d > 0 ? `▲${Math.abs(d)}` : d < 0 ? `▼${Math.abs(d)}` : `—`;
 return `<span class="move ${cls}" title="Rank movement vs previous release">${label}</span>`;
 }
 function momentumLabel(a){
 if(a.rankMove === null || a.rankMove === undefined) return 'NEW';
 const d = a.rankMove || 0;
 if(d > 0) return `▲ ${Math.abs(d)} ranks`;
 if(d < 0) return `▼ ${Math.abs(d)} ranks`;
 return '— flat';
 }
 function sortedAgencies(){
 let list = [...state.agencies];
 const q = state.search.trim().toLowerCase();
 if(q) list = list.filter(a=>a.agency.toLowerCase().includes(q) || a.symbol.toLowerCase().includes(q));
 if(state.sort === 'value') list.sort((a,b)=>b.metalValue-a.metalValue || b.efficiencyBonus-a.efficiencyBonus || b.metalPoints-a.metalPoints || b.gp-a.gp || a.agency.localeCompare(b.agency));
 if(state.sort === 'efficiency') list.sort((a,b)=>b.efficiencyBonus-a.efficiencyBonus || b.efficiency-a.efficiency || b.metalValue-a.metalValue || a.agency.localeCompare(b.agency));
 return list;
 }
 function portfolioHtml(a){
 const p = a.portfolio || {};
 const parts = [];
 if(p.gp) parts.push(`<span class="pill gp">GP×${p.gp}</span>`);
 if(p.gold) parts.push(`<span class="pill gold">G×${p.gold}</span>`);
 if(p.silver) parts.push(`<span class="pill silver">S×${p.silver}</span>`);
 if(p.bronze) parts.push(`<span class="pill bronze">B×${p.bronze}</span>`);
 parts.push(`<span class="pill eff">E: ${a.efficiencyBonus}pts</span>`);
 return parts.join('') || '<span style="color:var(--muted)">—</span>';
 }
 const NETWORK_RULES = [
 ['TBWA','TBWA'],
 ['VML','VML'],
 ['OGILVY','OGILVY'],
 ['MCCANN','MCCANN'],
 ['BBDO','BBDO'],
 ['ALMAPBBDO','BBDO'],
 ['DAVID','DAVID'],
 ['GUT','GUT'],
 ['DENTSU','DENTSU'],
 ['DDB','DDB'],
 ['FCB','FCB'],
 ['GREY','GREY'],
 ['AKQA','AKQA'],
 ['PUBLICIS','PUBLICIS'],
 ['LEPUB','LEPUB'],
 ['LEO','LEO'],
 ['SAATCHI','SAATCHI & SAATCHI'],
 ['BBH','BBH'],
 ['DROGA5','DROGA5'],
 ['R/GA','R/GA'],
 ['MULLENLOWE','MULLENLOWE'],
 ['LOLA','MULLENLOWE'],
 ['WIEDEN+KENNEDY','W+K'],
 ['WIEDEN + KENNEDY','W+K']
 ];
 function networkLabels(agency){
 const normalized = agency.toUpperCase().replace(/\\/g,' / ');
 const labels = new Set();
 const segments = normalized.split('/').map(s=>s.trim()).filter(Boolean);
 for(const segment of segments){
   for(const [needle,label] of NETWORK_RULES){
     if(segment.includes(needle)) labels.add(label);
   }
 }
 for(const [needle,label] of NETWORK_RULES){
   if(normalized.includes(needle)) labels.add(label);
 }
 return [...labels];
 }
 function networkSymbol(name){
 return name.split(/\s+/).filter(Boolean).map(w=>w[0]).join('').slice(0,5) || name.slice(0,5);
 }
 function rankNetworkItems(items, field){
 const ranked = [...items].filter(n=>Number(n[field] || 0) > 0).sort((a,b)=>b[field]-a[field] || a.name.localeCompare(b.name));
 const map = new Map();
 ranked.forEach((n,i)=>map.set(n.name, i+1));
 return map;
 }
 function networkMoveHtml(n){
 if(n.previousRank === null || n.previousRank === undefined) return `<span class="move flat" title="New in current ranking">—</span>`;
 const d = n.previousRank - n.currentRank;
 const cls = d > 0 ? 'up' : d < 0 ? 'down' : 'flat';
 const label = d > 0 ? `▲${Math.abs(d)}` : d < 0 ? `▼${Math.abs(d)}` : `—`;
 return `<span class="move ${cls}" title="Network ranking movement vs previous release">${label}</span>`;
 }
 function networkScores(){
 const map = new Map();
 AGENCIES.forEach(a=>{
   const labels = networkLabels(a.agency);
   if(!labels.length) return;
   labels.forEach(name=>{
     if(!map.has(name)) map.set(name,{name, symbol:networkSymbol(name), value:0, baselineValue:0, metalPoints:0, metals:0, offices:0});
     const item = map.get(name);
     item.value += Number(a.metalValue || 0);
     item.baselineValue += Number(a.baselineValue || 0);
     item.metalPoints += Number(a.metalPoints || 0);
     item.metals += Number(a.metals || 0);
     item.offices += 1;
   });
 });
 const items = [...map.values()];
 const current = rankNetworkItems(items, 'value');
 const previous = rankNetworkItems(items, 'baselineValue');
 items.forEach(n=>{
   n.currentRank = current.get(n.name);
   n.previousRank = previous.has(n.name) ? previous.get(n.name) : null;
 });
 return items.sort((a,b)=>b.value-a.value || a.name.localeCompare(b.name));
 }
 function renderTicker(){
 const top = networkScores().slice(0,16);
 const html = top.map(n=>`<span class="ticker-item"><b>${n.name}</b><span class="value">${fmt(n.value)}</span>${networkMoveHtml(n)}</span>`).join('');
 $('#tickerTrack').innerHTML = html + html;
 }
 function renderRows(){
 const list = sortedAgencies();
 if(!list.length){ $('#rows').innerHTML = '<div class="empty">No agencies found.</div>'; return; }
 $('#rows').innerHTML = list.map((a,i)=>{
 const id = `agency-${i}`;
 return `<div class="row" data-id="${id}" tabindex="0" role="button" aria-expanded="${state.expanded===a.agency}"><div class="rank"><span>${a.currentRank || i+1}</span></div><div class="agency">${a.agency}</div><div class="num"><span>${fmt(a.metalValue)}</span>${momentumHtml(a)}</div><div class="portfolio">${portfolioHtml(a)}</div></div><div class="detail ${state.expanded===a.agency?'open':''}"><div class="detail-inner"><div class="stat"><div class="stat-label">Value</div><div class="stat-value">${fmt(a.metalValue)}</div></div><div class="stat"><div class="stat-label">Base Value</div><div class="stat-value">${fmt(a.metalPoints)}</div></div><div class="stat"><div class="stat-label">E Bonus</div><div class="stat-value">+${a.efficiencyBonus}</div></div><div class="stat"><div class="stat-label">Rank Move</div><div class="stat-value">${momentumLabel(a)}</div></div><div class="stat"><div class="stat-label">Entered Cases</div><div class="stat-value">${a.enteredCases}</div></div><div class="stat"><div class="stat-label">Efficiency</div><div class="stat-value">${a.efficiency.toFixed(2)}</div></div><div class="stat"><div class="stat-label">Metals</div><div class="stat-value">${a.metals}</div></div></div></div>`;
 }).join('');
 $$('#rows .row').forEach(row=>{
 row.addEventListener('click',()=>{
 const idx = Number(row.dataset.id.replace('agency-',''));
 const agency = list[idx].agency;
 state.expanded = state.expanded === agency ? null : agency;
 renderRows();
 });
 row.addEventListener('keydown',(e)=>{ if(e.key==='Enter'||e.key===' '){ e.preventDefault(); row.click(); } });
 });
 }
 $$('.sort-button').forEach(btn=>{btn.addEventListener('click',()=>{state.sort = btn.dataset.sort;$$('.sort-button').forEach(b=>b.classList.toggle('active', b===btn));state.expanded = null;renderRows();});});
 $('#search').addEventListener('input',(e)=>{ state.search = e.target.value; state.expanded = null; renderRows(); });
 renderTicker();
 renderRows();
 